SELECT ?firstLabel ?secondLabel ?thirdLabel WHERE {
  {
    SELECT ?event WHERE {
      ?event wdt:P179 wd:Q1542651 ;
             wdt:P585 ?date .
    }
    ORDER BY DESC(?date) LIMIT 1
  }

  ?event p:P1344 ?participation1 .
  ?participation1 ps:P1344 ?first ;
                  pq:P1352 wd:Q940149 .

  ?event p:P1344 ?participation2 .
  ?participation2 ps:P1344 ?second ;
                  pq:P1352 wd:Q1249985 .

  ?event p:P1344 ?participation3 .
  ?participation3 ps:P1344 ?third ;
                  pq:P1352 wd:Q940150 .

  ?first rdfs:label ?firstLabel .
  ?second rdfs:label ?secondLabel .
  ?third rdfs:label ?thirdLabel .
  FILTER(LANG(?firstLabel) = "en" && LANG(?secondLabel) = "en" && LANG(?thirdLabel) = "en")
}

